<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n = norm(v);       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">% →  n = norm(v)           (uses LinearAlgebra)</span></span>
